  '절연저항': { en: 'Insulation resistance', ru: 'Сопротивление изоляции' },
  '12V 보조전원': { en: '12V auxiliary power', ru: 'Вспомогательное питание 12 В' },
  '관련 센서 데이터': { en: 'Related sensor data', ru: 'Связанные данные датчиков' },
  '제조사 기준 이하': { en: 'Below manufacturer criterion', ru: 'Ниже критерия производителя' },
  '차량 기준 우선': { en: 'Vehicle criterion takes priority', ru: 'Приоритет критерия автомобиля' },
  '상태별 기준 적용': { en: 'Apply criterion by state', ru: 'Применить критерий по состоянию' },
  '정상범위': { en: 'Normal range', ru: 'Нормальный диапазон' },
  '스캐너값': { en: 'Scanner value', ru: 'Значение сканера' },
