  '고전압 차량 안전 차단 가상실습': { en: 'High-Voltage Vehicle Safety Isolation Virtual Practice', ru: 'Виртуальная практика безопасного HV-отключения' },
  '차량 속도': { en: 'Vehicle Speed', ru: 'Скорость автомобиля' },
  '고전압 추정': { en: 'Estimated HV', ru: 'Оценка HV' },
  '배터리 SOC': { en: 'Battery SOC', ru: 'SOC батареи' },
  '작업 허가': { en: 'Work Permission', ru: 'Разрешение работы' },
  'IG OFF 전: 바퀴 회전 중': { en: 'Before IG OFF: wheels rotating', ru: 'До IG OFF: колеса вращаются' },
  '정지 확인': { en: 'Stop confirmed', ru: 'Остановка подтверждена' },
  'MSD 탈거 후 0V 검전 단계': { en: '0V check step after MSD removal', ru: 'Этап проверки 0 В после снятия MSD' },
  '접촉 금지': { en: 'Do not touch', ru: 'Не касаться' },
  '에너지 잔류 가능성 전제': { en: 'Assume residual energy may remain', ru: 'Предполагать остаточную энергию' },
